import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Chessboard } from 'react-chessboard';
import { Chess } from 'chess.js';
import PlayerTimer from './PlayerTimer';

// ── Board Themes ──
const BOARD_THEMES = {
  classic: {
    label: 'Classic',
    light: '#f0d9b5',
    dark: '#b58863',
  },
  dark: {
    label: 'Dark',
    light: '#334155',
    dark: '#1e293b',
  },
  green: {
    label: 'Green',
    light: '#eeeed2',
    dark: '#769656',
  },
};

// ── Piece unicode for captured display ──
const PIECE_UNICODE = {
  wp: '♙', wn: '♘', wb: '♗', wr: '♖', wq: '♕',
  bp: '♟', bn: '♞', bb: '♝', br: '♜', bq: '♛',
};

const PIECE_VALUES = { p: 1, n: 3, b: 3, r: 5, q: 9 };

export default function ChessBoard({
  roomId,
  fen,
  onMove,
  currentPlayer,
  whitePlayer,
  blackPlayer,
  boardOrientation = 'white',
  isSpectator = false,
  gameStatus,
  timerData,
  spectatorCount = 0,
  floatingEmoji,
}) {
  const gameRef = useRef(new Chess());
  const containerRef = useRef(null);
  const [boardWidth, setBoardWidth] = useState(400);
  const [whiteTime, setWhiteTime] = useState(30);
  const [blackTime, setBlackTime] = useState(30);
  const [selectedSquare, setSelectedSquare] = useState(null);
  const [legalMoveStyles, setLegalMoveStyles] = useState({});
  const [illegalMoveMsg, setIllegalMoveMsg] = useState('');
  const [boardTheme, setBoardTheme] = useState(() => {
    return localStorage.getItem('chess-board-theme') || 'dark';
  });
  const [whiteCaptured, setWhiteCaptured] = useState([]); // pieces white captured (black pieces)
  const [blackCaptured, setBlackCaptured] = useState([]); // pieces black captured (white pieces)
  const [inCheck, setInCheck] = useState(false);

  // ── Responsive board sizing ──
  useEffect(() => {
    const updateSize = () => {
      if (containerRef.current) {
        const w = containerRef.current.offsetWidth;
        setBoardWidth(Math.min(w - 16, 560));
      }
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  // ── Update chess.js when fen changes ──
  useEffect(() => {
    if (fen && fen !== gameRef.current.fen()) {
      try {
        gameRef.current.load(fen);
        // Check detection
        setInCheck(gameRef.current.isCheck());
      } catch (e) {
        console.error('Invalid FEN:', e);
      }
    }
    // Clear selection on fen change
    setSelectedSquare(null);
    setLegalMoveStyles({});
  }, [fen]);

  // ── Track captured pieces from FEN ──
  useEffect(() => {
    if (!fen) return;
    const startingPieces = { p: 8, n: 2, b: 2, r: 2, q: 1 };
    const current = { w: { p: 0, n: 0, b: 0, r: 0, q: 0 }, b: { p: 0, n: 0, b: 0, r: 0, q: 0 } };

    const boardPart = fen.split(' ')[0];
    for (const char of boardPart) {
      if ('pnbrq'.includes(char)) current.b[char]++;
      else if ('PNBRQ'.includes(char)) current.w[char.toLowerCase()]++;
    }

    // What white captured = starting black pieces - remaining black pieces
    const wCaptured = [];
    const bCaptured = [];
    for (const piece of ['q', 'r', 'b', 'n', 'p']) {
      const blackMissing = startingPieces[piece] - current.b[piece];
      const whiteMissing = startingPieces[piece] - current.w[piece];
      for (let i = 0; i < blackMissing; i++) wCaptured.push(PIECE_UNICODE[`b${piece}`]);
      for (let i = 0; i < whiteMissing; i++) bCaptured.push(PIECE_UNICODE[`w${piece}`]);
    }
    setWhiteCaptured(wCaptured);
    setBlackCaptured(bCaptured);
  }, [fen]);

  // ── Material advantage calculation ──
  const calcAdvantage = (captured) => {
    let val = 0;
    const reverseMap = {};
    Object.entries(PIECE_UNICODE).forEach(([k, v]) => { reverseMap[v] = k; });
    for (const p of captured) {
      const key = reverseMap[p];
      if (key) val += PIECE_VALUES[key[1]] || 0;
    }
    return val;
  };
  const whiteAdvRaw = calcAdvantage(whiteCaptured) - calcAdvantage(blackCaptured);
  const whiteAdv = Math.max(0, whiteAdvRaw);
  const blackAdv = Math.max(0, -whiteAdvRaw);

  // ── Timer countdown based on server expiry ──
  useEffect(() => {
    if (!timerData || gameStatus !== 'playing') return;

    const calculateRemaining = () => {
      const expires = timerData.expiresAt ? timerData.expiresAt : Date.now() + 30000;
      return Math.max(0, Math.floor((expires - Date.now()) / 1000));
    };

    if (timerData.turn === 'w') {
      setWhiteTime(calculateRemaining());
      setBlackTime(30);
    } else {
      setBlackTime(calculateRemaining());
      setWhiteTime(30);
    }

    const interval = setInterval(() => {
      if (timerData.turn === 'w') {
        setWhiteTime((prev) => Math.max(0, prev - 1));
      } else {
        setBlackTime((prev) => Math.max(0, prev - 1));
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [timerData, gameStatus]);

  // ── Auto-dismiss illegal move message ──
  useEffect(() => {
    if (!illegalMoveMsg) return;
    const t = setTimeout(() => setIllegalMoveMsg(''), 2000);
    return () => clearTimeout(t);
  }, [illegalMoveMsg]);

  // ── Save board theme ──
  useEffect(() => {
    localStorage.setItem('chess-board-theme', boardTheme);
  }, [boardTheme]);

  const canMakeMove = () => {
    if (isSpectator) return false;
    if (gameStatus !== 'playing') return false;
    if (!currentPlayer) return false;
    const turn = gameRef.current.turn();
    return (
      (turn === 'w' && currentPlayer.color === 'white') ||
      (turn === 'b' && currentPlayer.color === 'black')
    );
  };

  // ── Compute legal move dots ──
  const showLegalMoves = useCallback((square) => {
    const game = gameRef.current;
    const moves = game.moves({ square, verbose: true });
    if (moves.length === 0) return {};

    const styles = {};
    // Highlight selected square in yellow
    styles[square] = { backgroundColor: 'rgba(255, 255, 0, 0.4)' };

    for (const move of moves) {
      if (move.captured) {
        // Red ring for capturable pieces
        styles[move.to] = {
          background: 'radial-gradient(circle, transparent 55%, rgba(239, 68, 68, 0.7) 55%)',
          borderRadius: '50%',
        };
      } else {
        // Green dot for empty squares
        styles[move.to] = {
          background: 'radial-gradient(circle, rgba(34, 197, 94, 0.6) 25%, transparent 25%)',
          borderRadius: '50%',
        };
      }
    }
    return styles;
  }, []);

  // ── Click-to-move handler ──
  const onSquareClick = (square) => {
    if (!canMakeMove()) return;
    const game = gameRef.current;

    if (selectedSquare) {
      // Try to make the move
      const move = game.move({
        from: selectedSquare,
        to: square,
        promotion: 'q',
      });

      if (move) {
        onMove({
          from: selectedSquare,
          to: square,
          promotion: 'q',
          san: move.san,
        });
        setSelectedSquare(null);
        setLegalMoveStyles({});
        return;
      }

      // If clicking a different own piece, select that instead
      const piece = game.get(square);
      if (piece && piece.color === game.turn()) {
        setSelectedSquare(square);
        setLegalMoveStyles(showLegalMoves(square));
        return;
      }

      // Illegal move
      setIllegalMoveMsg(`${square} is not a legal move`);
      setSelectedSquare(null);
      setLegalMoveStyles({});
      return;
    }

    // First click — select a piece
    const piece = game.get(square);
    if (piece && piece.color === game.turn()) {
      setSelectedSquare(square);
      setLegalMoveStyles(showLegalMoves(square));
    }
  };

  // ── Drag-to-move handler ──
  const onDrop = (sourceSquare, targetSquare) => {
    if (!canMakeMove()) return false;

    const game = gameRef.current;
    const move = game.move({
      from: sourceSquare,
      to: targetSquare,
      promotion: 'q',
    });
    if (!move) {
      setIllegalMoveMsg(`${targetSquare} is not a legal move`);
      return false;
    }

    onMove({
      from: sourceSquare,
      to: targetSquare,
      promotion: 'q',
      san: move.san,
    });

    setSelectedSquare(null);
    setLegalMoveStyles({});
    return true;
  };

  // ── Check highlight ──
  const getCheckStyles = () => {
    if (!inCheck) return {};
    const game = gameRef.current;
    const board = game.board();
    const turn = game.turn();

    for (let r = 0; r < 8; r++) {
      for (let c = 0; c < 8; c++) {
        const sq = board[r][c];
        if (sq && sq.type === 'k' && sq.color === turn) {
          const file = 'abcdefgh'[c];
          const rank = 8 - r;
          return {
            [`${file}${rank}`]: {
              backgroundColor: 'rgba(239, 68, 68, 0.6)',
              borderRadius: '50%',
            },
          };
        }
      }
    }
    return {};
  };

  // ── Combine all square styles ──
  const customSquareStyles = {
    ...legalMoveStyles,
    ...getCheckStyles(),
  };

  const theme = BOARD_THEMES[boardTheme] || BOARD_THEMES.dark;

  const turn = gameRef.current.turn();
  const topPlayer = boardOrientation === 'white' ? blackPlayer : whitePlayer;
  const bottomPlayer = boardOrientation === 'white' ? whitePlayer : blackPlayer;
  const topTime = boardOrientation === 'white' ? blackTime : whiteTime;
  const bottomTime = boardOrientation === 'white' ? whiteTime : blackTime;
  const isTopTurn = boardOrientation === 'white' ? turn === 'b' : turn === 'w';
  const isBottomTurn = boardOrientation === 'white' ? turn === 'w' : turn === 'b';
  const topColor = boardOrientation === 'white' ? 'black' : 'white';
  const bottomColor = boardOrientation === 'white' ? 'white' : 'black';
  const topCaptured = boardOrientation === 'white' ? blackCaptured : whiteCaptured;
  const bottomCaptured = boardOrientation === 'white' ? whiteCaptured : blackCaptured;
  const topAdv = boardOrientation === 'white' ? blackAdv : whiteAdv;
  const bottomAdv = boardOrientation === 'white' ? whiteAdv : blackAdv;

  return (
    <div ref={containerRef} className="w-full flex flex-col items-center gap-2">
      {/* Floating emoji */}
      {floatingEmoji && (
        <div className="emoji-float" style={{ top: '40%', left: '50%' }}>
          {floatingEmoji}
        </div>
      )}

      {/* Top Player Bar */}
      <PlayerTimer
        player={topPlayer}
        time={topTime}
        isActive={isTopTurn && gameStatus === 'playing'}
        color={topColor}
        captured={topCaptured}
        materialAdvantage={topAdv}
      />

      {/* Timer progress bar */}
      {gameStatus === 'playing' && isTopTurn && (
        <div className="w-full progress-bar" style={{ maxWidth: boardWidth }}>
          <div
            className="progress-fill bg-gradient-to-r from-red-500 to-gold-500 timer-bar"
            style={{ width: `${(topTime / 30) * 100}%` }}
          />
        </div>
      )}

      {/* Board */}
      <div
        className={`rounded-xl overflow-hidden shadow-2xl shadow-black/50 transition-all duration-300 relative ${
          !canMakeMove() && !isSpectator && gameStatus === 'playing' ? 'opacity-80' : ''
        }`}
      >
        <Chessboard
          position={fen}
          onPieceDrop={onDrop}
          onSquareClick={onSquareClick}
          boardOrientation={boardOrientation}
          boardWidth={boardWidth}
          customBoardStyle={{
            borderRadius: '12px',
          }}
          customDarkSquareStyle={{ backgroundColor: theme.dark }}
          customLightSquareStyle={{ backgroundColor: theme.light }}
          customSquareStyles={customSquareStyles}
          animationDuration={200}
          arePiecesDraggable={canMakeMove()}
        />
      </div>

      {/* Illegal move text */}
      {illegalMoveMsg && (
        <p className="illegal-move-text">{illegalMoveMsg}</p>
      )}

      {/* Timer progress bar */}
      {gameStatus === 'playing' && isBottomTurn && (
        <div className="w-full progress-bar" style={{ maxWidth: boardWidth }}>
          <div
            className="progress-fill bg-gradient-to-r from-gold-500 to-emerald-500 timer-bar"
            style={{ width: `${(bottomTime / 30) * 100}%` }}
          />
        </div>
      )}

      {/* Bottom Player Bar */}
      <PlayerTimer
        player={bottomPlayer}
        time={bottomTime}
        isActive={isBottomTurn && gameStatus === 'playing'}
        color={bottomColor}
        captured={bottomCaptured}
        materialAdvantage={bottomAdv}
      />

      {/* Bottom row: Spectator + Theme selector */}
      <div className="w-full max-w-[560px] flex items-center justify-between mt-1">
        {/* Spectator Badge */}
        {isSpectator && (
          <div className="badge-purple">
            <span>👁️</span> Spectating
          </div>
        )}
        {spectatorCount > 0 && (
          <div className="badge-blue">
            <span>👁</span> {spectatorCount} watching
          </div>
        )}

        {/* Board Theme Selector */}
        <div className="flex gap-1 ml-auto">
          {Object.entries(BOARD_THEMES).map(([key, t]) => (
            <button
              key={key}
              onClick={() => setBoardTheme(key)}
              title={t.label}
              className={`w-6 h-6 rounded-full border-2 transition-all ${
                boardTheme === key
                  ? 'border-gold-400 scale-110'
                  : 'border-transparent opacity-60 hover:opacity-100'
              }`}
              style={{
                background: `linear-gradient(135deg, ${t.light} 50%, ${t.dark} 50%)`,
              }}
            />
          ))}
        </div>
      </div>
    </div>
  );
}
